detail_find_rule:
js:
var res={};
var d=[];

var 顺序 = fetch("hiker://files/rules/Hood/cache/xmly.txt",{});
MY_URL = MY_URL.replace("true", 顺序);

d.push({
    title: "““切换列表顺序””",
    url: $('#noLoading#').lazyRule(() => {
        var txt = "hiker://files/rules/Hood/cache/xmly.txt";
        if(fetch(txt).includes("true")){
            writeFile(txt, "false");
        }else{
            writeFile(txt, "true");
        }
        refreshPage(false);
        return 'toast://请稍候…'
    }),
    col_type: 'text_center_1'
});

var num = MY_URL.match(/(\d*)\/20/)[1];
var htmls = [];
for (var s = 1; s <= num; s++) {htmls.push({url: MY_URL.replace(/\d*\/20/, s + "/20")});}
htmls = batchFetch(htmls);

for(var k = 0; k < num; k ++) {
    var json = JSON.parse(htmls[k]);
    var list = json.tracks.list;

    for (var i in list) {
        var listi = list[i];
        var title = listi.title.replace(/【.*?】|《.*?》|（[^上|中|下].*?）|\([^上|中|下].*?\)/g,"");
        var desc = "";

        if (title.length > 20) {
            desc = "↪" + title.substring(20);
            title = title.substring(0,20);
        }

        d.push({
            title: title,
            desc: desc + "♥" + listi.likes,
            url: listi.playUrl64
        }); 
    }
}

for(var b=0;b<3;b++){d.push({col_type: 'big_blank_block'});}

res.data=d;
setHomeResult(res);

